func progressPct(done, total int) int {
	if total == 0 {
		return 0
	}
	pct := (done * 100) / total
	if pct > 100 {
		return 100
	}
	return pct
}

func formatLayerNum(n int) string {
	return fmt.Sprintf("%d", n)
}

func formatPrimCount(n int) string {
	if n == 1 {
		return "1 primitive"
	}
	return fmt.Sprintf("%d primitives", n)
}

func layerSlug(n int) string {
	return fmt.Sprintf("layer/%d", n)
}

